<body>
<h1>🧩 Maze Explorer — 24 Bots</h1>
<div class="stats">
  <div id="completed">Completed: 0/24</div>
  <div id="timer">Time: 0</div>
  <button id="reset">New Maze</button>
</div>
<div id="maze"></div>

<script>
(function() {
"use strict";

/* ── PRNG (mulberry32) ─────────────────────────────────────── */
function mulberry32(seed) {
  return function() {
    seed |= 0; seed = seed + 0x6D2B79F5 | 0;
    var t = Math.imul(seed ^ seed >>> 15, 1 | seed);
    t = t + Math.imul(t ^ t >>> 7, 61 | t) ^ t;
    return ((t ^ t >>> 14) >>> 0) / 4294967296;
  };
}

/* ── Helpers ───────────────────────────────────────────────── */
var DIRS = [
  { name: 'n', dr: -1, dc:  0 },
  { name: 'e', dr:  0, dc:  1 },
  { name: 's', dr:  1, dc:  0 },
  { name: 'w', dr:  0, dc: -1 }
];
var OPP = { n:'s', e:'w', s:'n', w:'e' };

function ck(r, c) { return r * 65536 + c; }

function shuffle(arr, rng) {
  var a = arr.slice();
  for (var i = a.length - 1; i > 0; i--) {
    var j = (rng() * (i + 1)) | 0;
    var tmp = a[i]; a[i] = a[j]; a[j] = tmp;
  }
  return a;
}

/* ── Maze Game ─────────────────────────────────────────────── */
var ROWS = 21, COLS = 21; // odd sizes give nice DFS maze structure

function generateMaze(rng) {
  var walls = {};
  for (var r = 0; r < ROWS; r++) {
    for (var c = 0; c < COLS; c++) {
      walls[ck(r,c)] = { n:true, e:true, s:true, w:true };
    }
  }
  var stack = [{r:0, c:0}];
  var visited = {};
  visited[ck(0,0)] = true;

  while (stack.length > 0) {
    var top = stack[stack.length - 1];
    var nbrs = [];
    for (var d = 0; d < DIRS.length; d++) {
      var nr = top.r + DIRS[d].dr, nc = top.c + DIRS[d].dc;
      if (nr >= 0 && nr < ROWS && nc >= 0 && nc < COLS && !visited[ck(nr,nc)]) {
        nbrs.push({r:nr, c:nc, dir:DIRS[d]});
      }
    }
    if (nbrs.length > 0) {
      var next = nbrs[(rng() * nbrs.length)|0];
      delete walls[ck(top.r,top.c)][next.dir.name];
      delete walls[ck(next.r,next.c)][OPP[next.dir.name]];
      visited[ck(next.r,next.c)] = true;
      stack.push({r:next.r, c:next.c});
    } else {
      stack.pop();
    }
  }
  return walls;
}

function MazeGame() {
  this.reset();
}

MazeGame.prototype.reset = function(seed) {
  if (seed === undefined || seed === null) seed = ((Math.random()*2147483647)|0);
  else seed = seed | 0;
  this._rng = mulberry32(seed);
  this.seed = seed;

  this.size   = { rows: ROWS, cols: COLS };
  this.spawn  = { r: 0, c: 0 };
  this.exit   = { r: ROWS-1, c: COLS-1 };

  this._walls = generateMaze(this._rng);

  // ── bots ────────────────────────────────────────────────
  this.bots = [];
  for (var i = 0; i < 24; i++) {
    var bRng = mulberry32(seed ^ (i * 7919) ^ 0x9E3779B9);
    var dirOrder = shuffle(DIRS, bRng);

    this.bots.push({
      id: i,
      path: [{r:0, c:0}],          // chronological visit trace
      stack: [{r:0, c:0}],          // DFS stack (internal)
      deadEnds: [],                 // cells marked dead
      explored: {},                 // cellKey -> Set of dir names tried
      entryDir: null,               // direction we entered current cell from
      finished: false,
      finishTick: null,
      directionOrder: dirOrder,
      // animation state
      fromCell: {r:0, c:0},
      toCell:   {r:0, c:0},
      moveProgress: 1.0
    });
  }

  this.elapsed = 0;
  this._allFinished = false;
};

MazeGame.prototype.walls = function(r, c) {
  var w = this._walls[ck(r,c)];
  if (w) return { n:!!w.n, e:!!w.e, s:!!w.s, w:!!w.w };
  return { n:true, e:true, s:true, w:true };
};

/* ── single bot step ─────────────────────────────────────── */
MazeGame.prototype._stepBot = function(bot) {
  var curKey = ck(bot.stack[bot.stack.length-1].r, bot.stack[bot.stack.length-1].c);
  var prevPos = { r: bot.toCell.r, c: bot.toCell.c };

  // try forward moves
  var tried = 0;
  while (tried < bot.directionOrder.length) {
    var di = (bot._dirIdx || 0) + tried;
    if (di >= bot.directionOrder.length) break;
    var dir = bot.directionOrder[di];

    // skip already-explored directions
    if (!bot.explored[curKey]) bot.explored[curKey] = {};
    if (bot.explored[curKey][dir.name]) { tried++; continue; }

    // skip the direction we entered from (prevents immediate reversal)
    if (dir.name === bot.entryDir) { tried++; continue; }

    var w = this.walls(bot.stack[bot.stack.length-1].r, bot.stack[bot.stack.length-1].c);
    if (!w[dir.name]) {
      // passage exists — check target isn't a dead-end cell we already marked
      var nr = bot.stack[bot.stack.length-1].r + dir.dr;
      var nc = bot.stack[bot.stack.length-1].c + dir.dc;
      var nKey = ck(nr,nc);

      // allow moving to exit even if it was somehow marked (shouldn't happen)
      var isExit = (nr === this.exit.r && nc === this.exit.c);
      var isDeadEnd = bot.deadEnds.indexOf(nKey) !== -1;

      if (!isDeadEnd || isExit) {
        // move forward
        bot.explored[curKey][dir.name] = true;
        var newCell = {r: nr, c: nc};
        bot.stack.push(newCell);
        bot.path.push({r: nr, c: nc});

        // mark opposite direction as explored at the NEW cell so we don't reverse
        if (!bot.explored[nKey]) bot.explored[nKey] = {};
        bot.explored[nKey][OPP[dir.name]] = true;
        bot.entryDir = OPP[dir.name];
        bot._dirIdx = 0;

        // animation
        bot.fromCell = {r: prevPos.r, c: prevPos.c};
        bot.toCell   = {r: nr, c: nc};
        bot.moveProgress = 0;

        if (isExit) {
          bot.finished = true;
          bot.finishTick = this.elapsed + 1; // will be set after elapsed++ in tick()
        }
        return true;
      }
    }
    tried++;
  }

  // no forward move — backtrack one step
  if (bot.stack.length > 1) {
    var popped = bot.stack.pop();
    bot.deadEnds.push(ck(popped.r, popped.c));
    // don't add duplicates
    while (bot.deadEnds.indexOf(ck(popped.r, popped.c)) !== bot.deadEnds.lastIndexOf(ck(popped.r, popped.c))) {
      bot.deadEnds.pop();
    }

    var backTo = bot.stack[bot.stack.length-1];
    bot.path.push({r: backTo.r, c: backTo.c});

    // update entry dir for the cell we're going to
    // find which direction from backTo leads to popped
    var dr2 = popped.r - backTo.r, dc2 = popped.c - backTo.c;
    bot.entryDir = null;
    for (var d2 = 0; d2 < DIRS.length; d2++) {
      if (DIRS[d2].dr === dr2 && DIRS[d2].dc === dc2) {
        bot.entryDir = OPP[DIRS[d2].name]; // we'll be going BACK into backTo from popped's direction
        break;
      }
    }

    bot.fromCell = {r: prevPos.r, c: prevPos.c};
    bot.toCell   = {r: backTo.r, c: backTo.c};
    bot.moveProgress = 0;
    return true;
  }
  return false; // stuck (shouldn't happen in connected maze)
};

/* ── tick(n) ─────────────────────────────────────────────── */
MazeGame.prototype.tick = function(n) {
  for (var t = 0; t < n; t++) {
    if (this._allFinished) break;
    this.elapsed++;

    var anySearching = false;
    for (var i = 0; i < this.bots.length; i++) {
      var bot = this.bots[i];
      if (bot.finished) continue;
      this._stepBot(bot);
      // fix finishTick to match elapsed
      if (bot.finished && bot.finishTick === this.elapsed - 1 + 1) {
        // already correct since we set it before elapsed++ was wrong
      }
      if (!bot.finished) anySearching = true;
    }
    // re-set finish ticks now that elapsed is final for this tick
    for (var j = 0; j < this.bots.length; j++) {
      if (this.bots[j].finished && this.bots[j].finishTick === null) {
        this.bots[j].finishTick = this.elapsed;
      }
    }
    if (!anySearching) this._allFinished = true;
  }
};

/* ── API snapshot helpers ────────────────────────────────── */
MazeGame.prototype.getCompleted = function() {
  var count = 0;
  for (var i = 0; i < this.bots.length; i++) if (this.bots[i].finished) count++;
  return count;
};

/* ── instantiate ─────────────────────────────────────────── */
var game = new MazeGame();

window.game = {
  tick: function(n) { game.tick(n); },
  reset: function(seed) { game.reset(seed); },
  get elapsed()    { return game.elapsed; },
  get size()       { return { rows: game.size.rows, cols: game.size.cols }; },
  get spawn()      { return { r: game.spawn.r, c: game.spawn.c }; },
  get exit()       { return { r: game.exit.r, c: game.exit.c }; },
  walls: function(r,c) { return game.walls(r,c); },
  get bots() {
    var result = [];
    for (var i = 0; i < game.bots.length; i++) {
      var b = game.bots[i];
      // convert deadEnds keys to {r,c}
      var deArr = [];
      for (var k = 0; k < b.deadEnds.length; k++) {
        deArr.push({ r: (b.deadEnds[k] >> 16) & 0xFFFF, c: b.deadEnds[k] & 0xFFFF });
      }
      result.push({
        path:       b.path.slice(),
        deadEnds:   deArr,
        finishTick: b.finishTick
      });
    }
    return result;
  },
  get completed() { return game.getCompleted(); }
};

/* ── Rendering ───────────────────────────────────────────── */
var CELL = 28;
var CANVAS_W = CELL * COLS;
var CANVAS_H = CELL * ROWS;

var mazeEl = document.getElementById('maze');
var canvas = document.createElement('canvas');
canvas.width = CANVAS_W; canvas.height = CANVAS_H;
mazeEl.appendChild(canvas);
var ctx = canvas.getContext('2d');

// 24 distinct bot colours
var BOT_CLR = [
  '#FF1744','#00E676','#2979FF','#FFEA00','#D500F9','#00BFA5',
  '#FF6D00','#F50057','#64FFDA','#448AFF','#FF9100','#CA62FD',
  '#1DE9B6','#FF3D00','#7C4DFF','#FF1744','#00E5FF','#AEEA00',
  '#FDD835','#AA00FF','#FF6E40','#6200EA','#00BFA5','#FFD600'
];

var animId = null;
var lastFrame = performance.now();

function render() {
  var now = performance.now();
  var dt = (now - lastFrame) / 1000;
  if (dt > 0.1) dt = 0.1; // cap delta
  lastFrame = now;

  ctx.clearRect(0, 0, CANVAS_W, CANVAS_H);

  // background
  ctx.fillStyle = '#0d1b2a';
  ctx.fillRect(0, 0, CANVAS_W, CANVAS_H);

  // cells
  for (var r = 0; r < ROWS; r++) {
    for (var c = 0; c < COLS; c++) {
      var x = c * CELL, y = r * CELL;
      ctx.fillStyle = '#1b2838';
      ctx.fillRect(x+1, y+1, CELL-2, CELL-2);

      // spawn highlight
      if (r === game.spawn.r && c === game.spawn.c) {
        ctx.fillStyle = 'rgba(33,150,243,0.25)';
        ctx.fillRect(x+1, y+1, CELL-2, CELL-2);
      }
      // exit highlight (pulsing)
      if (r === game.exit.r && c === game.exit.c) {
        var pulse = 0.15 + 0.12 * Math.sin(now / 300);
        ctx.fillStyle = 'rgba(0,230,118,' + pulse + ')';
        ctx.fillRect(x+1, y+1, CELL-2, CELL-2);
      }
    }
  }

  // walls
  ctx.strokeStyle = '#e94560';
  ctx.lineWidth = 2.5;
  ctx.lineCap = 'round';
  for (var r2 = 0; r2 < ROWS; r2++) {
    for (var c2 = 0; c2 < COLS; c2++) {
      var w = game.walls(r2, c2);
      var x2 = c2 * CELL, y2 = r2 * CELL;
      ctx.beginPath();
      if (w.n) { ctx.moveTo(x2, y2); ctx.lineTo(x2+CELL, y2); }
      if (w.e) { ctx.moveTo(x2+CELL, y2); ctx.lineTo(x2+CELL, y2+CELL); }
      if (w.s) { ctx.moveTo(x2, y2+CELL); ctx.lineTo(x2+CELL, y2+CELL); }
      if (w.w) { ctx.moveTo(x2, y2); ctx.lineTo(x2, y2+CELL); }
      ctx.stroke();
    }
  }

  // bots with smooth interpolation
  var speed = 6; // cells per second for animation
  for (var bi = 0; bi < game.bots.length; bi++) {
    var bot = game.bots[bi];

    // advance progress
    if (bot.moveProgress < 1.0) {
      bot.moveProgress += dt * speed;
      if (bot.moveProgress >= 1.0) {
        bot.moveProgress = 1.0;
        bot.fromCell = {r: bot.toCell.r, c: bot.toCell.c};
      }
    }

    var ease = bot.moveProgress < 0.5
      ? 2 * bot.moveProgress * bot.moveProgress
      : 1 - Math.pow(-2*bot.moveProgress + 2, 2) / 2;

    var fx = (bot.fromCell.c + 0.5) * CELL;
    var fy = (bot.fromCell.r + 0.5) * CELL;
    var tx = (bot.toCell.c   + 0.5) * CELL;
    var ty = (bot.toCell.r   + 0.5) * CELL;

    var bx = fx + (tx - fx) * ease;
    var by = fy + (ty - fy) * ease;

    // glow
    ctx.fillStyle = BOT_CLR[bi % BOT_CLR.length];
    ctx.globalAlpha = 0.3;
    ctx.beginPath(); ctx.arc(bx, by, CELL*0.42, 0, Math.PI*2); ctx.fill();
    ctx.globalAlpha = 1;

    // dot
    ctx.fillStyle = BOT_CLR[bi % BOT_CLR.length];
    ctx.beginPath(); ctx.arc(bx, by, CELL*0.3, 0, Math.PI*2); ctx.fill();

    // inner highlight
    ctx.fillStyle = 'rgba(255,255,255,0.4)';
    ctx.beginPath(); ctx.arc(bx - CELL*0.06, by - CELL*0.06, CELL*0.12, 0, Math.PI*2); ctx.fill();

    // finished indicator ring
    if (bot.finished) {
      ctx.strokeStyle = '#fff';
      ctx.lineWidth = 1.5;
      ctx.beginPath(); ctx.arc(bx, by, CELL*0.38, 0, Math.PI*2); ctx.stroke();
    }
  }

  animId = requestAnimationFrame(render);
}
render();

/* ── UI updates (throttled) ──────────────────────────────── */
var uiTimer = 0;
function updateUI() {
  document.getElementById('completed').textContent = 'Completed: ' + game.completed + '/24';
  document.getElementById('timer').textContent     = 'Time: ' + game.elapsed;
  setTimeout(updateUI, 100);
}
updateUI();

/* ── Reset button ────────────────────────────────────────── */
document.getElementById('reset').addEventListener('click', function() {
  game.reset();
});

})();
</script>
</body>
</html>
