<script>
(function(){ "use strict";

/* ═══════════════ PRNG ═══════════════ */
function mulberry32(s){return function(){s|=0;s=s+0x6D2B79F5|0;var t=Math.imul(s^s>>>15,1|s);t=t+Math.imul(t^t>>>7,61|t)^t;return((t^t>>>14)>>>0)/4294967296;};}

/* ═══════════════ Helpers ═══════════════ */
var DIRS=[{n:'n',dr:-1,dc:0},{n:'e',dr:0,dc:1},{n:'s',dr:1,dc:0},{n:'w',dr:0,dc:-1}];
var OPP={n:'s',e:'w',s:'n',w:'e'};
function ck(r,c){return r*65536+c;}
function shuffle(a,rng){a=a.slice();for(var i=a.length-1;i>0;i--){var j=(rng()*(i+1))|0;var t=a[i];a[i]=a[j];a[j]=t;}return a;}

/* ═══════════════ Maze generation (randomised DFS) ═══════════════ */
function genMaze(rng){
  var W={};
  for(var r=0;r<ROWS;r++)for(var c=0;c<COLS;c++)W[ck(r,c)]={n:1,e:1,s:1,w:1};
  var stk=[{r:0,c:0}]; var vis={}; vis[ck(0,0)]=1;
  while(stk.length){
    var top=stk[stk.length-1], nb=[];
    for(var d=0;d<4;d++){var nr=top.r+DIRS[d].dr,nc=top.c+DIRS[d].dc;
      if(nr>=0&&nr<ROWS&&nc>=0&&nc<COLS&&!vis[ck(nr,nc)])nb.push({r:nr,c:nc,d:DIRS[d]});}
    if(nb.length){var nx=nb[(rng()*nb.length)|0];
      W[ck(top.r,top.c)][nx.d.n]=0; W[ck(nx.r,nx.c)][OPP[nx.d.n]]=0;
      vis[ck(nx.r,nx.c)]=1; stk.push({r:nx.r,c:nx.c});}
    else stk.pop();
  }
  return W;
}

/* ═══════════════ Game ═══════════════ */
var ROWS=21, COLS=21;

function MazeGame(){this.reset();}

MazeGame.prototype.reset=function(seed){
  if(seed===undefined||seed===null) seed=((Math.random()*2147483647)|0); else seed=seed|0;
  this._rng=mulberry32(seed); this.seed=seed;
  this.size={rows:ROWS,cols:COLS};
  this.spawn={r:0,c:0}; this.exit={r:ROWS-1,c:COLS-1};
  this._W=genMaze(this._rng);

  this.bots=[];
  for(var i=0;i<24;i++){
    var brng=mulberry32(seed^(i*7919)^0x9E3779B9);
    this.bots.push({
      id:i, path:[{r:0,c:0}], stk:[{r:0,c:0}], deadEnds:[],
      explored:{}, entryDir:null, _dirIdx:0,
      finished:false, finishTick:null,
      dirOrder:shuffle(DIRS,brng),
      fromCell:{r:0,c:0}, toCell:{r:0,c:0}, prog:1.0
    });
  }
  this.elapsed=0; this._done=false;
};

MazeGame.prototype.walls=function(r,c){
  var w=this._W[ck(r,c)];
  return{ n:!!(w&&w.n), e:!!(w&&w.e), s:!!(w&&w.s), w:!!(w&&w.w) };
};

MazeGame.prototype._step=function(bot){
  var cur=bot.stk[bot.stk.length-1];
  var curK=ck(cur.r,cur.c);
  var prev={r:bot.toCell.r,c:bot.toCell.c};

  // try forward moves in preferred direction order
  for(var tried=0;tried<4;tried++){
    var di=(bot._dirIdx+tried)%4;
    var dir=bot.dirOrder[di];

    if(!bot.explored[curK]) bot.explored[curK]={};
    if(bot.explored[curK][dir.n]) continue;       // already tried this direction
    if(dir.n===bot.entryDir) continue;             // don't reverse into where we came from

    var w=this.walls(cur.r,cur.c);
    if(!w[dir.n]){                                 // passage open?
